// Bicep: create a resource group at subscription scope
// Deploy with: az deployment sub create --template-file rg.bicep --location eastus

targetScope = 'subscription'

param workload string
param environment string
param location string = 'eastus'
param regionAbbr string = 'eastus'

var tags = {
  Environment: environment
  Application: workload
  Owner: '${workload}-team@contoso.com'
  ManagedBy: 'bicep'
}

// App resource group: VMs, App Service, AKS
resource rgApp 'Microsoft.Resources/resourceGroups@2024-03-01' = {
  name: 'rg-${workload}-app-${environment}-${regionAbbr}'
  location: location
  tags: tags
}

// Data resource group: SQL, Storage, Redis
resource rgData 'Microsoft.Resources/resourceGroups@2024-03-01' = {
  name: 'rg-${workload}-data-${environment}-${regionAbbr}'
  location: location
  tags: tags
}

// Network resource group: VNet, NSG, Private endpoints
resource rgNetwork 'Microsoft.Resources/resourceGroups@2024-03-01' = {
  name: 'rg-${workload}-network-${environment}-${regionAbbr}'
  location: location
  tags: tags
}

output appRg string   = rgApp.name
output dataRg string  = rgData.name
output networkRg string = rgNetwork.name

# Terraform: resource groups with per-workload module pattern

# modules/resource-groups/main.tf
variable "workload"     { type = string }
variable "environment"  { type = string }
variable "location"     { type = string }
variable "region_abbr"  { type = string }
variable "tags"         { type = map(string) }

resource "azurerm_resource_group" "app" {
  name     = "rg-${var.workload}-app-${var.environment}-${var.region_abbr}"
  location = var.location
  tags     = var.tags
}

resource "azurerm_resource_group" "data" {
  name     = "rg-${var.workload}-data-${var.environment}-${var.region_abbr}"
  location = var.location
  tags     = var.tags
}

resource "azurerm_resource_group" "network" {
  name     = "rg-${var.workload}-network-${var.environment}-${var.region_abbr}"
  location = var.location
  tags     = var.tags
}

output "app_rg_name"     { value = azurerm_resource_group.app.name }
output "data_rg_name"    { value = azurerm_resource_group.data.name }
output "network_rg_name" { value = azurerm_resource_group.network.name }

# root main.tf — invoke the module for each workload/environment combination
module "payments_prod" {
  source      = "./modules/resource-groups"
  workload    = "payments"
  environment = "prod"
  location    = "East US"
  region_abbr = "eastus"
  tags = {
    Environment = "prod"
    Application = "payments"
    CostCenter  = "cc-123"
    Owner       = "payments-team@contoso.com"
  }
}

module "payments_dev" {
  source      = "./modules/resource-groups"
  workload    = "payments"
  environment = "dev"
  location    = "East US"
  region_abbr = "eastus"
  tags = {
    Environment = "dev"
    Application = "payments"
    CostCenter  = "cc-123"
    Owner       = "payments-team@contoso.com"
  }
}

